var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이 정도 규모의 전투는 저도 오랜만이네요.","JPN":"この規模の戦闘は僕も久々ですね。","ENG":"It's been a while since I've been in a fight this big.","TWN":"好久沒經歷這種大場面了。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 어깨가 조금 뻐근한데요.","JPN":"ハハ、少し肩が凝ってきました。","ENG":"Haha, my shoulder's actually a bit sore.","TWN":"哈哈～我肩膀有點痠痛的感覺。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"방심하지 마라, 나유빈. 실전이란……","JPN":"油断するな、イチノセ。戦いとは……","ENG":"Do not let your guard down. When it comes to real combat…","TWN":"羅瑜斌，不可大意！所謂的戰場……"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>단순한 전투력 비교가 아니다. </color>","JPN":"<color=#ffd34c>単なる戦闘力の比較ではない。</color>","ENG":"<color=#ffd34c>It's not a matter of comparing combat power. </color>","TWN":"<color=#ffd34c>不是只比戰力。 </color>"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>건장한 어른도 꼬맹이가 쏜 총알에 맞으면 죽는다.</color>","JPN":"<color=#ffd34c>丈夫な大人も子どもが撃った銃弾に当たれば死ぬ。</color>","ENG":"<color=#ffd34c>A bullet fired by a child is just as deadly.</color>","TWN":"<color=#ffd34c>強壯的大人被小鬼的槍打到也是會沒命的。</color>"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론 기억하고 있습니다.","JPN":"もちろん覚えていますよ。","ENG":"Yeah, I remember it all.","TWN":"我當然記得。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"좋든 싫든 지금의 제가 있는 건 스승님의 가르침 덕분이니까요.","JPN":"良くも悪くも、今の僕がいるのは師匠の教えのおかげですから。","ENG":"Whether I like it or not, I'm still here thanks to your teachings.","TWN":"無論喜不喜歡，都是因為師父的教導才會有現在的我。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……다행인지 불행인지 모르겠군.","JPN":"……幸か不幸か、わからないな。","ENG":"I'm not sure if that's good or bad.","TWN":"……不知道是幸還是不幸。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그나저나 자칭 성녀인 것치고는 하는 행동들이 꽤나 역설적이군요.","JPN":"ところで自称聖女にしては、やっていることがかなり矛盾していますね。","ENG":"Anyway, this so-called Saintess did everything to NOT live up to her name, it seems.","TWN":"不過，你自稱為聖女，所做的行為卻完全相反呢！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"백성들의 기억을 조작해서 침식체로 부리고, 죽은 시체를 되살려내 부리다니……","JPN":"民の記憶をねつ造して侵食体として操り、死者を蘇らせるなんて……","ENG":"She manipulated the memories of her people to enslave them as C.O.s, even raising them from the dead…","TWN":"控制百姓的記憶，把他們當作侵蝕體使喚，還把死人弄活操控他們……"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이래서야 마녀와 다를 것도 없지 않나요?","JPN":"これじゃあ魔女と呼んだほうが正しいのでは？","ENG":"She's practically a witch, isn't she?","TWN":"照你的行為看來應該稱為魔女吧？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"제 신실함을 당신에게 증명할 필요는 없습니다, 이방인.","JPN":"私の信実をあなたに証明する必要はありません、異邦人。","ENG":"I have no need to prove my piety to you, outsider.","TWN":"我是聖女還是魔女用不著你這個外邦人來說嘴。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저의 신은 바로 구원자님이고, 저는 그 분의 사제니까요.","JPN":"私の神は救世主様であり、私はあの方の司祭ですから。","ENG":"My Savior is my god, and I am his priestess.","TWN":"我的神只有一位，就是救贖者大人，而我是他的祭司。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"당당하게 나서기엔 슬슬 모아 뒀던 언데드들도 바닥나지 않았나?","JPN":"強がっているが、そろそろかき集めたアンデッドも底をついたようだな。","ENG":"Aren't you running out of zombies rather fast to act so confident?","TWN":"你自己出手的話，那些你收集那麼久的活死人也不會像這樣一個都不剩。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"무익한 싸움은 이제 포기해라, 강령술사.","JPN":"無益な戦いはもうやめろ、降霊術師。","ENG":"You have nothing to gain from this fight, necromancer. Yield.","TWN":"放棄無謂的掙扎吧，降靈術師！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"바닥났다고요?","JPN":"底をついたですって？","ENG":"Running out, you say?","TWN":"一個都不剩？！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그럴 리가. 지금부터가 시작입니다.","JPN":"まさか。これからが始まりです。","ENG":"Quite the contrary. I'm just getting started.","TWN":"真是笑話！現在才正要開始呢！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"무슨…… 음?!","JPN":"なんの……む！？","ENG":"What do you mean… Huh?!","TWN":"什……麼？！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"두 사람 다 조심하세요!","JPN":"二人とも気を付けてください！","ENG":"Watch out, guys!","TWN":"你們兩個小心！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"클리포트 인자 반응입니다, 그 중에서도 이건……!!","JPN":"クリフォト・ファクター反応です、それもこれは……！！","ENG":"I'm reading Qliphoth Factor signatures… and worse yet, it's…","TWN":"是卡巴拉因子反應！而且當中……！！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};